    # even: minimize (dist_self - dist_opp*0.6) -> race closer advantage
    # odd: minimize (dist_self*1.2 - dist_opp) -> more deny opponent
    even_turn = (observation["turn_index"] % 2 == 0)
    best = None
    for rx, ry in resources:
